BenchmarkRunner.Run<TextAnalyzerBenchmarks>(config, args);

[MemoryDiagnoser]
public class TextAnalyzerBenchmarks
{
    private TextAnalyzer _analyzer = null!;

    // A representative paragraph with varied word lengths
    private const string SampleText =
        "The quick brown fox jumps over the lazy dog while the energetic cat " +
        "sprints across the beautiful garden filled with extraordinary colorful " +
        "flowers and magnificent ancient trees that have been growing for " +
        "centuries in this wonderfully peaceful and remarkably serene environment " +
        "where animals and nature coexist harmoniously throughout the seasons " +
        "bringing joy and tranquility to everyone who visits this enchanting place";

    [GlobalSetup]
    public void Setup()
    {
        _analyzer = new TextAnalyzer(SampleText);
    }

    [Benchmark]
    public double AverageWordLength() => _analyzer.AverageWordLength();

    [Benchmark]
    public object WordLengthHistogram() => _analyzer.WordLengthHistogram();

    [Benchmark]
    public int UniqueWordCount() => _analyzer.UniqueWordCount();
}

